import{a as e}from"./chunk-XFATBM7I.js";import"./chunk-IFGU66OU.js";var t={meta:e,sections:[{id:"overview",title:"Overview",blocks:[{type:"markdown",value:"The smallest technology section from the source question set, answered first. These scenarios test whether you can connect Kubernetes status to application, networking, and lifecycle behavior."}]},{id:"interview-questions",title:"Interview Questions and Answers",blocks:[{type:"interviewQa",items:[{question:"A pod keeps restarting but its application logs show nothing. How do you debug it?",answer:"Run `kubectl describe pod` and inspect container state, exit code, events, probes, OOMKilled, image/config errors, and node pressure. Read the prior container with `kubectl logs --previous`. If it exits before logging, inspect the entrypoint, command, mounted config/secrets, security context, and runtime events."},{question:"How do you ship a Spring Boot service with zero downtime?",answer:"Use a RollingUpdate with multiple replicas, correct readiness probes, `maxUnavailable: 0`, controlled `maxSurge`, and enough capacity. Make schema/API changes backward-compatible, wait for readiness before traffic, use a PodDisruptionBudget, and automatically roll back on health or SLO regression."},{question:"A pod is terminating. What happens to in-flight requests, and how do you shut down cleanly?",answer:"Kubernetes sets a deletion timestamp, removes the pod from service endpoints, runs `preStop`, and sends SIGTERM. The app should fail readiness, stop accepting work, drain requests/consumers, and exit before `terminationGracePeriodSeconds`; otherwise Kubernetes sends SIGKILL."},{question:"Kubernetes says the service is healthy, but users receive 503 errors. Where do you start?",answer:"Trace client \u2192 ingress/gateway \u2192 Service \u2192 EndpointSlice \u2192 pod. Verify selectors and ports, ready endpoints, ingress routes/TLS, network policies, sidecars, and upstream timeouts. A liveness check only proves the process is alive; readiness must prove it can serve traffic."},{question:"You have ten pods, but traffic reaches only two. How do you investigate?",answer:"Check EndpointSlices for all ready pods, Service selectors, readiness failures, topology-aware routing, session affinity, ingress/upstream connection reuse, and zonal skew. Compare per-pod request metrics and test direct pod/service traffic before changing replica count."},{question:"One pod uses much more CPU than other replicas. How do you find the cause?",answer:"Compare request distribution, partition or shard ownership, scheduled jobs, cache warm-up, retries, and pod limits/throttling. Capture application profiles or thread dumps from the hot pod, correlate traces and logs by route/key, then verify whether traffic skew or unique work explains it."}]}]}]},o=t;export{o as default};
